"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[23],{5226(e,n,t){t.r(n),t.d(n,{assets:()=>h,contentTitle:()=>a,default:()=>c,frontMatter:()=>o,metadata:()=>r,toc:()=>d});var i=t(4848),s=t(8453);const o={},a="Prologue: The Way of Disappearing",r={id:"mirror-realm/prologue",title:"Prologue: The Way of Disappearing",description:"\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/mirror-realm/prologue.md",sourceDirName:"mirror-realm",slug:"/mirror-realm/prologue",permalink:"/MythogenEngine/en/docs/mirror-realm/prologue",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Theme 08: The Xbox Gamble and Crisis\u2014Strategic Value of an AI Testing Ground vs. Commercialization Risks",permalink:"/MythogenEngine/en/docs/ai-war/xbox"},next:{title:"Chapter 1: The Least Worst Choice",permalink:"/MythogenEngine/en/docs/mirror-realm/ch01"}},h={},d=[];function l(e){const n={em:"em",h1:"h1",header:"header",hr:"hr",p:"p",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"prologue-the-way-of-disappearing",children:"Prologue: The Way of Disappearing"})}),"\n",(0,i.jsx)(n.p,{children:"\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501"}),"\n",(0,i.jsx)(n.p,{children:"A NOTE ON THIS TRANSLATION"}),"\n",(0,i.jsx)(n.p,{children:"You are reading a working draft."}),"\n",(0,i.jsx)(n.p,{children:"The original is in Chinese (Cantonese and Mandarin\neditions). This English version was produced with\nAI assistance \u2014 the same class of tools the book\nitself examines."}),"\n",(0,i.jsx)(n.p,{children:"I could have waited for a polished human translation.\nThat would have been the safer choice. But this book\nis about what happens when we wait for safer choices.\nIt felt dishonest to hold the book back while people\nwho might need it continue to sit in the same rooms\nit describes."}),"\n",(0,i.jsx)(n.p,{children:"So this draft goes out as it is. Imperfect. In motion.\nBeing refined."}),"\n",(0,i.jsx)(n.p,{children:"If you find passages that don't land, that's real\nfeedback. I'd like to hear it."}),"\n",(0,i.jsx)(n.p,{children:"\u2014 Nebula Walker\nApril 2026\nportaly.cc/Mythogen"}),"\n",(0,i.jsx)(n.p,{children:"\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.em,{children:'"If this book can save even one person\u2014one person is worth it."'})," ",(0,i.jsx)(n.em,{children:"\u2014\u2014 Lin Zhao-ming"})]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Location: Mirror Realm \xb7 Emerald Isle Study (Parallel Universe 15)\nTime: 25 FEB 1026, Present"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming returned to his study and didn't turn on the light."}),"\n",(0,i.jsx)(n.p,{children:"Outside the window was the sea. The color of the water couldn't be seen in the night, only a few scattered lights in the distance. Looking in this direction, it was beautiful."}),"\n",(0,i.jsx)(n.p,{children:"He didn't turn around. He knew what was behind him\u2014at the foot of the mountain, the lights of the factory district, a completely different kind of brightness."}),"\n",(0,i.jsx)(n.p,{children:'The sounds of the New Year gathering were still ringing in his ears, but he only remembered one sentence\u2014someone pouring drinks, speaking in a tone as casual as discussing the weather: "Hey, did you know someone jumper again over in the power department? Right near the Aura Synthesis building."'}),"\n",(0,i.jsx)(n.p,{children:"Then the topic shifted. Someone called for a toast."}),"\n",(0,i.jsx)(n.p,{children:"He tapped to illuminate his Mirror Screen terminal."}),"\n",(0,i.jsx)(n.p,{children:'The light from the screen reflected on his face. He didn\'t move. In the Mirror Realm, he knew exactly how long this news of death would survive\u2014seventy-two hours, or less. It wasn\'t deletion; it was dilution. First, discussions about "personal emotional management," then "workplace stress," and then, that person\'s name would disappear into a pile of corporate wellbeing push notifications, until it finally became like a closed ticket, utterly impossible to find.'}),"\n",(0,i.jsx)(n.p,{children:"He opened the search bar and typed in a few code words that only insiders could string together."}),"\n",(0,i.jsx)(n.p,{children:"The thread appeared. People were still talking."}),"\n",(0,i.jsx)(n.p,{children:"He glanced at the timestamp."}),"\n",(0,i.jsx)(n.p,{children:"Almost time."}),"\n",(0,i.jsx)(n.p,{children:"This wasn't his first time keeping track of such a countdown. It was always the same\u2014you had to race against the algorithm, to save those words before the system could identify them. Not to do anything with them, but because if you couldn't even manage to witness it in time, that person would truly never have existed at all."}),"\n",(0,i.jsx)(n.p,{children:"He started taking screenshots."}),"\n",(0,i.jsx)(n.p,{children:"The study was quiet; his wife was already asleep. Sitting in the darkness, the screen light scrolled down line by line. Inside were terms he recognized\u2014testing, pressure, yield rate, 24-hour standby\u2014pieced together in unfamiliar ways, reading like they were talking about something else entirely, but he knew exactly what they meant."}),"\n",(0,i.jsx)(n.p,{children:"He knew better than anyone the exact shape of what lurked behind those code words."}),"\n",(0,i.jsx)(n.p,{children:"Four years. It took him four years to learn how to recognize that shape."}),"\n",(0,i.jsx)(n.p,{children:"Save. Encrypt. Close."}),"\n",(0,i.jsx)(n.p,{children:"He took his hands off the keyboard and sat in the darkness, unmoving."}),"\n",(0,i.jsx)(n.p,{children:"The sound of a car passed by outside the window, very distant, and then vanished."}),"\n",(0,i.jsx)(n.p,{children:"He thought of the person pouring drinks tonight. The next second, they were toasting. No one stopped. It wasn't malice, it was\u2014he couldn't find another word for it\u2014it was that the person's death had absolutely no impact on the operation of that table."}),"\n",(0,i.jsx)(n.p,{children:"He opened an old folder. Inside was something he had started writing four years ago, only to abandon it after a few paragraphs."}),"\n",(0,i.jsx)(n.p,{children:"He looked at those few lines of text."}),"\n",(0,i.jsx)(n.p,{children:"Then he moved the cursor to the last line and began to type."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"It wasn't out of righteous indignation, nor a sense of mission."}),"\n",(0,i.jsx)(n.p,{children:"It was: If I don't leave something behind in these seventy-two hours, maybe there really will be nothing left at all."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Location: Mirror Realm \xb7 Emerald Isle Study (Parallel Universe 15)\nTime: 8 NOV 1024 (One year, three months, and seventeen days ago)"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:'That thread he had once seen. He clicked on it. "This article has been deleted." He tried a few different keywords. Nothing. He used vaguer terms. He found one, posting date, November 1024. Someone in the post asked, "Where\'s the news?" There was no reply below. The post just sat there, and no one said anything else.'}),"\n",(0,i.jsx)(n.p,{children:"He remembered that PTT post. He had seen it with his own eyes. And he watched it vanish."}),"\n",(0,i.jsx)(n.p,{children:"An R&D engineer at Mist Valley Tech, responsible for the Mirror Screen terminal's electronic core, specifically running the Aura Synthesis project. Committed suicide due to excessive pressure."}),"\n",(0,i.jsx)(n.p,{children:"When he died, Lin Zhao-ming was still inside that company. The news spread in hushed tones; three hours later, no one mentioned it again. At noon on November 14, 1024, Team Building proceeded as usual. No one brought it up, no one thought about it. The existence of that person was erased from that very moment."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming constantly checked PTT that night. A thread would appear, and he would watch it get deleted. Change boards, search again, deleted again. In less than a week, a total blackout."}),"\n",(0,i.jsx)(n.p,{children:"That person, it was as if they had never existed at all."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"But Lin Zhao-ming knew he had existed."}),"\n",(0,i.jsx)(n.p,{children:"Because someone knew him. Because when that post existed, Lin Zhao-ming had read every single word. Because he recognized every detail in that post\u2014endless testing, not knowing what mistake to admit to, three to five-hour meetings where the goal wasn't communication, but distortion."}),"\n",(0,i.jsx)(n.p,{children:'The AI at the time was still in its "earnestly talking nonsense" phase. The AI confidently declared that if this were true, the system would definitely be able to find clues; yet it scoured the data and found nothing. So the AI began to emphasize: if this were true, it couldn\'t possibly leave no trace.'}),"\n",(0,i.jsx)(n.p,{children:"Just like that, a living human being, a vivid testament of blood and tears, ultimately ended up with even the AI questioning his reality."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"That was a person."}),"\n",(0,i.jsx)(n.p,{children:'Not data. Not an isolated case. Not collateral evidence of a systemic problem. It was a person, with a name, with colleagues who knew him, someone who had asked "Where\'s the news?" in that post, and never received an answer.'}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming knew of two people closely."}),"\n",(0,i.jsx)(n.p,{children:"From what he heard at dinner tables, there were many more."}),"\n",(0,i.jsx)(n.p,{children:"He wasn't using those lives to tell a story. He just refused to believe that those people died for absolutely nothing. So many died, there couldn't be nothing left."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"The media didn't report it, because of advertising revenue."}),"\n",(0,i.jsx)(n.p,{children:"The mods deleted the posts, because of board rules."}),"\n",(0,i.jsx)(n.p,{children:"The family didn't speak up, because they couldn't win the fight."}),"\n",(0,i.jsx)(n.p,{children:"The colleagues didn't speak up, because the next one could be them."}),"\n",(0,i.jsx)(n.p,{children:"The company didn't acknowledge it, because of legal."}),"\n",(0,i.jsx)(n.p,{children:'The Ministry of Labor didn\'t open a case, because it "occurred outside of working hours."'}),"\n",(0,i.jsx)(n.p,{children:"There was no mastermind. Everyone had their own reasons. Added together, it equaled disappearance."}),"\n",(0,i.jsx)(n.p,{children:"It wasn't that someone gave an order to make him disappear. It was that everyone with the power to make him exist, after running their own calculations, chose to let him disappear."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming had looked up the numbers."}),"\n",(0,i.jsx)(n.p,{children:"After finding that number, he closed his browser."}),"\n",(0,i.jsx)(n.p,{children:"The number itself didn't surprise him. That was the most terrifying part\u2014when he saw that number, his first thought wasn't \"how is this possible,\" it was \"that's less than what I've seen with my own eyes.\""}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He was an almost impossible witness."}),"\n",(0,i.jsx)(n.p,{children:"He had the technical knowledge to judge the causality between the deaths and the system.\nHe had the insider perspective, having spent four years inside that structure.\nHe had the time, because he had already been laid off. He had savings.\nHe had the motive, because he knew that if he didn't write it, those people would truly never have existed."}),"\n",(0,i.jsx)(n.p,{children:"Even if only one person reads this book, recognizes the place they are in, and chooses not to continue\u2014"}),"\n",(0,i.jsx)(n.p,{children:"One person is worth it."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He opened a new document."}),"\n",(0,i.jsx)(n.p,{children:"He wasn't out to prove anything. He didn't have backend logs, no written confirmation from anyone, no complete chain of evidence, and he couldn't publish any internal data."}),"\n",(0,i.jsx)(n.p,{children:"He only had the fragments of four years, and the things he had seen with his own eyes."}),"\n",(0,i.jsx)(n.p,{children:"The system told him: You are merely speculating."}),"\n",(0,i.jsx)(n.p,{children:"Maybe."}),"\n",(0,i.jsx)(n.p,{children:"But what he knew, was what he knew."}),"\n",(0,i.jsx)(n.p,{children:"Four years ago, he predicted they might be this kind of people. He chose to assume they weren't. He just did the work."}),"\n",(0,i.jsx)(n.p,{children:"He began to write."})]})}function c(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>a,x:()=>r});var i=t(6540);const s={},o=i.createContext(s);function a(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);